# 技术设计文档

_Spring Boot 自动配置源码教学实现_

---

## 📋 设计概述

### 架构风格
- **核心模式：** SPI (Service Provider Interface)
- **扩展点：** 基于现有 IOC 容器扩展
- **设计原则：** 简化版 Spring Boot，保留核心机制

### 核心组件

```
┌─────────────────────────────────────────────────────────┐
│                    用户配置类                              │
│              @EnableAutoConfiguration                    │
└────────────────────┬────────────────────────────────────┘
                     │
                     ▼
┌─────────────────────────────────────────────────────────┐
│          EnableAutoConfigurationImportSelector          │
│  - 读取 spring.factories                                 │
│  - 加载自动配置类列表                                     │
│  - 应用条件注解过滤                                       │
└────────────────────┬────────────────────────────────────┘
                     │
                     ▼
┌─────────────────────────────────────────────────────────┐
│              自动配置类列表                               │
│  - DemoAutoConfiguration                                │
│  - XxxAutoConfiguration                                 │
└────────────────────┬────────────────────────────────────┘
                     │
                     ▼
┌─────────────────────────────────────────────────────────┐
│              条件注解判断                                 │
│  - OnClassCondition                                     │
│  - OnBeanCondition                                      │
│  - OnPropertyCondition                                  │
└────────────────────┬────────────────────────────────────┘
                     │
                     ▼
┌─────────────────────────────────────────────────────────┐
│              实例化 Bean                                  │
│         注册到 IOC 容器                                    │
└─────────────────────────────────────────────────────────┘
```

---

## 🏗️ 详细设计

### 1. 注解设计

#### 1.1 @EnableAutoConfiguration

```java
package cn.code.annotation;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 启用自动配置
 * 
 * 作用：标记配置类，触发自动配置机制
 * 原理：通过@Import 导入 EnableAutoConfigurationImportSelector
 */
@Target(ElementType.TYPE)
@Retention(RetentionPolicy.RUNTIME)
@Import(EnableAutoConfigurationImportSelector.class)  // 核心
public @interface EnableAutoConfiguration {

    /**
     * 排除的自动配置类
     */
    Class<?>[] exclude() default {};
}
```

#### 1.2 @Conditional 系列注解

```java
// @ConditionalOnClass.java
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Documented
@Conditional(OnClassCondition.class)
public @interface ConditionalOnClass {
    Class<?>[] value() default {};
    String[] name() default {};
}

// @ConditionalOnMissingBean.java
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Documented
@Conditional(OnBeanCondition.class)
public @interface ConditionalOnMissingBean {
    Class<?>[] value() default {};
    String[] name() default {};
}

// @ConditionalOnProperty.java
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Documented
@Conditional(OnPropertyCondition.class)
public @interface ConditionalOnProperty {
    String prefix() default "";
    String name();
    String havingValue() default "true";
    boolean matchIfMissing() default false;
}
```

---

### 2. 核心类设计

#### 2.1 EnableAutoConfigurationImportSelector

```java
package cn.code.autoconfigure;

import cn.code.annotation.EnableAutoConfiguration;
import java.io.IOException;
import java.net.URL;
import java.util.*;

/**
 * 自动配置导入选择器
 * 
 * 核心职责：
 * 1. 读取 META-INF/spring.factories
 * 2. 解析自动配置类列表
 * 3. 应用条件注解过滤
 * 4. 应用 exclude 排除
 */
public class EnableAutoConfigurationImportSelector {

    private static final String FACTORIES_RESOURCE_LOCATION = 
        "META-INF/spring.factories";

    private static final String ENABLE_AUTO_CONFIGURATION_KEY = 
        "org.springframework.boot.autoconfigure.EnableAutoConfiguration";

    /**
     * 选择自动配置类
     */
    public List<String> selectImports(AnnotationMetadata metadata) {
        // 1. 获取 exclude 配置
        Map<String, Object> attributes = 
            metadata.getAnnotationAttributes(
                EnableAutoConfiguration.class.getName()
            );
        Class<?>[] excludes = (Class<?>[]) attributes.get("exclude");

        // 2. 加载所有配置
        List<String> configurations = loadFactoryNames();

        // 3. 应用 exclude
        applyExcludes(configurations, excludes);

        // 4. 应用条件注解过滤
        configurations = filter(configurations);

        return configurations;
    }

    /**
     * 读取 spring.factories
     */
    private List<String> loadFactoryNames() {
        List<String> result = new ArrayList<>();
        try {
            Enumeration<URL> urls = 
                Thread.currentThread().getContextClassLoader()
                    .getResources(FACTORIES_RESOURCE_LOCATION);

            while (urls.hasMoreElements()) {
                URL url = urls.nextElement();
                Properties properties = loadProperties(url);
                String factories = properties.getProperty(
                    ENABLE_AUTO_CONFIGURATION_KEY
                );
                if (factories != null) {
                    result.addAll(
                        Arrays.asList(factories.split(","))
                    );
                }
            }
        } catch (IOException e) {
            // 静默处理，spring.factories 不存在时不报错
            System.out.println(
                "Warning: spring.factories not found, skip auto-configuration"
            );
        }
        return result;
    }

    /**
     * 应用条件注解过滤
     */
    private List<String> filter(List<String> configurations) {
        List<String> filtered = new ArrayList<>();
        for (String config : configurations) {
            if (matchesConditions(config)) {
                filtered.add(config);
            }
        }
        return filtered;
    }

    /**
     * 判断是否满足条件
     */
    private boolean matchesConditions(String configClassName) {
        // 读取配置类的注解
        // 调用 Condition.matches() 判断
        // 多个条件是 AND 逻辑
        try {
            Class<?> configClass = Class.forName(configClassName);
            Conditional[] conditionals = 
                configClass.getAnnotationsByType(Conditional.class);

            for (Conditional conditional : conditionals) {
                Condition condition = 
                    conditional.value().newInstance();
                if (!condition.matches(this, configClass)) {
                    return false;
                }
            }
            return true;
        } catch (Exception e) {
            // 配置类加载失败，跳过
            System.out.println(
                "Warning: Failed to load config class: " + configClassName
            );
            return false;
        }
    }
}
```

---

#### 2.2 Condition 接口

```java
package cn.code.autoconfigure;

/**
 * 条件接口
 * 
 * 所有条件注解都需要实现此接口
 */
public interface Condition {
    /**
     * 判断是否满足条件
     * 
     * @param context 条件上下文
     * @param metadata 注解元数据
     * @return true-满足条件，false-不满足
     */
    boolean matches(ConditionContext context, 
                    AnnotationMetadata metadata);
}

// 条件上下文
public interface ConditionContext {
    ClassLoader getClassLoader();
    boolean containsBean(String beanName);
    String getProperty(String key);
}
```

---

#### 2.3 OnClassCondition

```java
package cn.code.autoconfigure;

public class OnClassCondition implements Condition {

    @Override
    public boolean matches(ConditionContext context, 
                          AnnotationMetadata metadata) {
        // 获取@ConditionalOnClass 注解
        Map<String, Object> attributes = 
            metadata.getAnnotationAttributes(
                ConditionalOnClass.class.getName()
            );

        if (attributes == null) {
            return true;  // 没有注解，默认满足
        }

        Class<?>[] classes = (Class<?>[]) attributes.get("value");
        String[] classNames = (String[]) attributes.get("name");

        // 检查 value 指定的类
        for (Class<?> clazz : classes) {
            try {
                Class.forName(clazz.getName());
            } catch (ClassNotFoundException e) {
                return false;  // 类不存在，不满足条件
            }
        }

        // 检查 name 指定的类（字符串形式）
        for (String className : classNames) {
            try {
                Class.forName(className);
            } catch (ClassNotFoundException e) {
                return false;
            }
        }

        return true;  // 所有类都存在
    }
}
```

---

#### 2.4 OnBeanCondition

```java
package cn.code.autoconfigure;

public class OnBeanCondition implements Condition {

    @Override
    public boolean matches(ConditionContext context, 
                          AnnotationMetadata metadata) {
        // 获取@ConditionalOnMissingBean 注解
        Map<String, Object> attributes = 
            metadata.getAnnotationAttributes(
                ConditionalOnMissingBean.class.getName()
            );

        if (attributes == null) {
            return true;
        }

        Class<?>[] classes = (Class<?>[]) attributes.get("value");
        String[] names = (String[]) attributes.get("name");

        // 检查 Bean 是否不存在
        for (Class<?> clazz : classes) {
            if (context.containsBean(clazz.getName())) {
                return false;  // Bean 已存在，不满足"缺失"条件
            }
        }

        for (String name : names) {
            if (context.containsBean(name)) {
                return false;
            }
        }

        return true;  // 所有 Bean 都不存在
    }
}
```

---

#### 2.5 OnPropertyCondition

```java
package cn.code.autoconfigure;

public class OnPropertyCondition implements Condition {

    @Override
    public boolean matches(ConditionContext context, 
                          AnnotationMetadata metadata) {
        // 获取@ConditionalOnProperty 注解
        Map<String, Object> attributes = 
            metadata.getAnnotationAttributes(
                ConditionalOnProperty.class.getName()
            );

        if (attributes == null) {
            return true;
        }

        String prefix = (String) attributes.get("prefix");
        String name = (String) attributes.get("name");
        String havingValue = (String) attributes.get("havingValue");
        boolean matchIfMissing = 
            (boolean) attributes.get("matchIfMissing");

        // 构建完整属性名
        String fullKey = (prefix != null ? prefix + "." : "") + name;

        // 获取属性值
        String value = context.getProperty(fullKey);

        if (value == null) {
            return matchIfMissing;  // 属性不存在时的行为
        }

        return value.equals(havingValue);
    }
}
```

