package cn.code.annotation;

import cn.code.autoconfigure.EnableAutoConfigurationImportSelector;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 启用自动配置
 * 
 * 作用：标记配置类，触发自动配置机制
 * 原理：通过@Import 导入 EnableAutoConfigurationImportSelector
 * 
 * 使用示例：
 * ```java
 * @EnableAutoConfiguration
 * public class Application {
 *     public static void main(String[] args) {
 *         // 启动应用
 *     }
 * }
 * ```
 * 
 * @author 小虾 🦐
 * @version 1.0
 */
@Target(ElementType.TYPE)
@Retention(RetentionPolicy.RUNTIME)
@Import(EnableAutoConfigurationImportSelector.class)  // 核心：导入自动配置选择器
public @interface EnableAutoConfiguration {

    /**
     * 排除的自动配置类
     * 
     * 使用场景：当某个自动配置类不符合需求时，可以通过此属性排除
     * 
     * 示例：
     * ```java
     * @EnableAutoConfiguration(exclude = {DemoAutoConfiguration.class})
     * ```
     * 
     * @return 要排除的自动配置类数组
     */
    Class<?>[] exclude() default {};
}

package cn.code.annotation;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 导入配置类
 * 
 * 作用：导入其他配置类到当前配置中
 * 原理：被导入的类会被实例化并注册到 IOC 容器
 * 
 * 使用示例：
 * ```java
 * @Configuration
 * @Import({AConfig.class, BConfig.class})
 * public class AppConfig {
 * }
 * ```
 * 
 * @author 小虾 🦐
 * @version 1.0
 */
@Target(ElementType.TYPE)
@Retention(RetentionPolicy.RUNTIME)
public @interface Import {

    /**
     * 要导入的配置类
     * 
     * @return 配置类数组
     */
    Class<?>[] value();
}

package cn.code.annotation;

import cn.code.autoconfigure.Condition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 条件注解
 * 
 * 作用：标注在配置类或 Bean 方法上，只有满足条件时才会加载
 * 原理：通过 Condition 接口的 matches 方法判断是否满足条件
 * 
 * 使用示例：
 * ```java
 * @Configuration
 * @Conditional(OnClassCondition.class)
 * public class DemoAutoConfiguration {
 *     @Bean
 *     public DemoService demoService() {
 *         return new DemoService();
 *     }
 * }
 * ```
 * 
 * @author 小虾 🦐
 * @version 1.0
 * @see Condition
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
public @interface Conditional {

    /**
     * 条件实现类
     * 
     * @return Condition 实现类
     */
    Class<? extends Condition> value();
}

package cn.code.annotation;

import cn.code.autoconfigure.OnClassCondition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 类路径条件注解
 * 
 * 作用：当类路径存在指定类时，配置类或 Bean 才会被加载
 * 原理：通过 OnClassCondition 检查类是否存在
 * 
 * 使用示例：
 * ```java
 * @Configuration
 * @ConditionalOnClass(DemoService.class)
 * public class DemoAutoConfiguration {
 *     @Bean
 *     public DemoService demoService() {
 *         return new DemoService();
 *     }
 * }
 * ```
 * 
 * 边界场景：
 * - 无参数时：始终满足条件
 * - 多个类：AND 逻辑，所有类都存在才满足
 * 
 * @author 小虾 🦐
 * @version 1.0
 * @see OnClassCondition
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Conditional(OnClassCondition.class)
public @interface ConditionalOnClass {

    /**
     * 需要存在的类
     * 
     * @return 类数组
     */
    Class<?>[] value() default {};

    /**
     * 需要存在的类名（字符串形式）
     * 
     * 使用场景：当类不在编译期依赖中，只在运行时存在
     * 
     * @return 类名数组
     */
    String[] name() default {};
}

package cn.code.annotation;

import cn.code.autoconfigure.OnBeanCondition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * Bean 缺失条件注解
 * 
 * 作用：当容器中不存在指定 Bean 时，配置类或 Bean 才会被加载
 * 原理：通过 OnBeanCondition 检查 Bean 是否存在
 * 
 * 使用示例：
 * ```java
 * @Configuration
 * public class DemoAutoConfiguration {
 *     
 *     @Bean
 *     @ConditionalOnMissingBean
 *     public DemoService demoService() {
 *         return new DemoService();
 *     }
 * }
 * ```
 * 
 * 边界场景：
 * - 无参数时：检查返回类型的 Bean 是否存在
 * - 指定 value：检查指定类型的 Bean 是否存在
 * - 指定 name：检查指定名称的 Bean 是否存在
 * 
 * @author 小虾 🦐
 * @version 1.0
 * @see OnBeanCondition
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Conditional(OnBeanCondition.class)
public @interface ConditionalOnMissingBean {

    /**
     * 需要检查的 Bean 类型
     * 
     * @return 类型数组
     */
    Class<?>[] value() default {};

    /**
     * 需要检查的 Bean 名称
     * 
     * @return 名称数组
     */
    String[] name() default {};
}

package cn.code.annotation;

import cn.code.autoconfigure.OnPropertyCondition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 属性条件注解
 * 
 * 作用：当配置属性满足条件时，配置类或 Bean 才会被加载
 * 原理：通过 OnPropertyCondition 检查属性值
 * 属性来源：System.getProperty() + application.properties
 * 
 * 使用示例：
 * ```java
 * @Configuration
 * @ConditionalOnProperty(prefix = "demo", name = "enabled", havingValue = "true")
 * public class DemoAutoConfiguration {
 *     @Bean
 *     public DemoService demoService() {
 *         return new DemoService();
 *     }
 * }
 * ```
 * 
 * 边界场景：
 * - 属性不存在时：根据 matchIfMissing 决定
 * - havingValue 默认为 "true"
 * - prefix 用于构建完整属性名
 * 
 * @author 小虾 🦐
 * @version 1.0
 * @see OnPropertyCondition
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Conditional(OnPropertyCondition.class)
public @interface ConditionalOnProperty {

    /**
     * 属性前缀
     * 
     * 示例：prefix = "demo", name = "enabled" → 完整属性名 "demo.enabled"
     * 
     * @return 前缀
     */
    String prefix() default "";

    /**
     * 属性名
     * 
     * @return 属性名
     */
    String name();

    /**
     * 匹配的值
     * 
     * @return 期望的属性值
     */
    String havingValue() default "true";

    /**
     * 属性不存在时是否匹配
     * 
     * @return true-属性不存在时也匹配，false-不匹配
     */
    boolean matchIfMissing() default false;
}

package cn.code.autoconfigure;

import cn.code.annotation.EnableAutoConfiguration;
import cn.code.annotation.Import;

import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.util.*;

/**
 * 自动配置导入选择器
 * 
 * 核心职责：
 * 1. 读取 META-INF/spring.factories
 * 2. 解析自动配置类列表
 * 3. 应用条件注解过滤
 * 4. 应用 exclude 排除
 * 
 * 工作原理：
 * - 通过@Import 被@EnableAutoConfiguration 导入
 * - 实现 ImportSelector 接口（简化版直接处理）
 * - 返回需要加载的自动配置类名列表
 * 
 * @author 小虾 🦐
 * @version 1.0
 * @see EnableAutoConfiguration
 */
public class EnableAutoConfigurationImportSelector {

    /**
     * spring.factories 文件位置
     */
    private static final String FACTORIES_RESOURCE_LOCATION = 
        "META-INF/spring.factories";

    /**
     * spring.factories 中的键名
     */
    private static final String ENABLE_AUTO_CONFIGURATION_KEY = 
        "org.springframework.boot.autoconfigure.EnableAutoConfiguration";

    /**
     * 选择自动配置类
     * 
     * @param importClassName 导入类的类名（本例中未使用）
     * @return 自动配置类名列表
     */
    public List<String> selectImports(String importClassName) {
        // 1. 加载所有配置
        List<String> configurations = loadFactoryNames();

        // 2. 过滤（应用条件注解）
        configurations = filter(configurations);

        return configurations;
    }

    /**
     * 读取 spring.factories
     * 
     * 文件格式示例：
     * ```properties
     * org.springframework.boot.autoconfigure.EnableAutoConfiguration=\
     * cn.code.starter.demo.DemoAutoConfiguration,\
     * cn.code.starter.another.AnotherAutoConfiguration
     * ```
     * 
     * @return 自动配置类名列表
     */
    public List<String> loadFactoryNames() {
        List<String> result = new ArrayList<>();

        try {
            // 使用 ClassLoader 枚举所有 spring.factories 资源
            Enumeration<URL> urls = 
                Thread.currentThread().getContextClassLoader()
                    .getResources(FACTORIES_RESOURCE_LOCATION);

            while (urls.hasMoreElements()) {
                URL url = urls.nextElement();
                System.out.println("Loading spring.factories from: " + url);

                Properties properties = loadProperties(url);
                String factories = properties.getProperty(
                    ENABLE_AUTO_CONFIGURATION_KEY
                );

                if (factories != null && !factories.trim().isEmpty()) {
                    // 分割并清理
                    String[] factoryArray = factories.split(",");
                    for (String factory : factoryArray) {
                        String trimmed = factory.trim();
                        // 跳过注释和空行
                        if (!trimmed.isEmpty() && !trimmed.startsWith("#")) {
                            result.add(trimmed);
                        }
                    }
                }
            }

            System.out.println("Loaded " + result.size() + " auto-configuration classes");

        } catch (IOException e) {
            // 边界处理：spring.factories 不存在时静默跳过，不报错
            System.out.println(
                "Warning: spring.factories not found, skip auto-configuration"
            );
        }

        return result;
    }

    /**
     * 加载 Properties 文件
     */
    private Properties loadProperties(URL url) throws IOException {
        Properties properties = new Properties();
        try (InputStream is = url.openStream()) {
            properties.load(is);
        }
        return properties;
    }

    /**
     * 过滤配置类（应用条件注解）
     * 
     * @param configurations 所有配置类
     * @return 满足条件的配置类
     */
    private List<String> filter(List<String> configurations) {
        List<String> filtered = new ArrayList<>();

        for (String config : configurations) {
            if (matchesConditions(config)) {
                filtered.add(config);
                System.out.println("Auto-configuration loaded: " + config);
            } else {
                System.out.println("Auto-configuration skipped: " + config);
            }
        }

        return filtered;
    }

    /**
     * 判断是否满足条件
     * 
     * 核心逻辑：
     * 1. 读取配置类的@Conditional 注解
     * 2. 调用 Condition.matches() 判断
     * 3. 多个条件是 AND 逻辑（所有条件都满足才返回 true）
     * 
     * @param configClassName 配置类名
     * @return true-满足条件，false-不满足
     */
    private boolean matchesConditions(String configClassName) {
        try {
            // 加载配置类
            Class<?> configClass = Class.forName(configClassName);

            // 获取所有@Conditional 注解
            Conditional[] conditionals = 
                configClass.getAnnotationsByType(Conditional.class);

            // 如果没有条件注解，默认满足
            if (conditionals == null || conditionals.length == 0) {
                return true;
            }

            // 所有条件都必须满足（AND 逻辑）
            for (Conditional conditional : conditionals) {
                Class<? extends Condition> conditionClass = conditional.value();
                Condition condition = conditionClass.newInstance();

                if (!condition.matches(null, null)) {
                    return false;  // 一个不满足就返回 false
                }
            }

            return true;  // 所有条件都满足

        } catch (ClassNotFoundException e) {
            // 配置类不存在，记录警告并跳过
            System.out.println(
                "Warning: Config class not found: " + configClassName
            );
            return false;

        } catch (Exception e) {
            // 其他异常（如实例化失败），记录警告并跳过
            System.out.println(
                "Warning: Failed to process config class: " + configClassName + 
                ", error: " + e.getMessage()
            );
            return false;
        }
    }
}

