package cn.code.autoconfigure;

import cn.code.annotation.ConditionalOnClass;

import java.util.Map;

/**
 * 类路径条件判断实现
 * 
 * 作用：判断类路径是否存在指定类
 * 对应注解：@ConditionalOnClass
 * 
 * 判断逻辑：
 * 1. 获取@ConditionalOnClass 注解的 value 和 name 属性
 * 2. 尝试加载每个类
 * 3. 所有类都存在返回 true，任何一个不存在返回 false
 * 
 * 边界场景：
 * - 无参数时：返回 true（始终满足）
 * - 类加载失败：返回 false
 * 
 * @author 小虾 🦐
 * @version 1.0
 * @see ConditionalOnClass
 */
public class OnClassCondition implements Condition {

    @Override
    public boolean matches(ConditionContext context, AnnotationMetadata metadata) {
        // 简化实现：直接通过反射读取注解
        // 实际 Spring 使用 ASM 读取字节码，不加载类

        if (metadata == null) {
            return true;  // 没有元数据，默认满足
        }

        // 获取注解属性（简化版，实际需要从 metadata 获取）
        // 这里通过反射读取当前类的注解
        try {
            // 从 metadata 获取类名
            String className = metadata.getClassName();
            Class<?> annotatedClass = Class.forName(className);

            ConditionalOnClass conditionalOnClass = 
                annotatedClass.getAnnotation(ConditionalOnClass.class);

            if (conditionalOnClass == null) {
                return true;  // 没有注解，默认满足
            }

            // 检查 value 指定的类
            Class<?>[] classes = conditionalOnClass.value();
            for (Class<?> clazz : classes) {
                try {
                    Class.forName(clazz.getName());
                } catch (ClassNotFoundException e) {
                    System.out.println(
                        "Condition failed: Class not found - " + clazz.getName()
                    );
                    return false;  // 类不存在，不满足条件
                }
            }

            // 检查 name 指定的类（字符串形式）
            String[] classNames = conditionalOnClass.name();
            for (String name : classNames) {
                if (name != null && !name.isEmpty()) {
                    try {
                        Class.forName(name);
                    } catch (ClassNotFoundException e) {
                        System.out.println(
                            "Condition failed: Class not found - " + name
                        );
                        return false;
                    }
                }
            }

            return true;  // 所有类都存在

        } catch (Exception e) {
            // 异常情况返回 false
            System.out.println(
                "OnClassCondition error: " + e.getMessage()
            );
            return false;
        }
    }
}

