# 技术设计文档

_Spring Boot 自动配置源码教学实现_

---

## 📋 架构设计

### 整体架构

```
┌─────────────────────────────────────────────────────────┐
│                    用户配置类                              │
│              @EnableAutoConfiguration                    │
└────────────────────┬────────────────────────────────────┘
                     │ @Import
                     ▼
┌─────────────────────────────────────────────────────────┐
│      EnableAutoConfigurationImportSelector              │
│      实现 ImportSelector 接口                             │
│  - selectImports()                                      │
│  - loadFactoryNames()                                   │
│  - filter()                                             │
└────────────────────┬────────────────────────────────────┘
                     │ 读取
                     ▼
┌─────────────────────────────────────────────────────────┐
│              META-INF/spring.factories                  │
│  org.springframework.boot.autoconfigure.\               │
│  EnableAutoConfiguration=\                              │
│  cn.code.starter.demo.DemoAutoConfiguration             │
└────────────────────┬────────────────────────────────────┘
                     │
                     ▼
┌─────────────────────────────────────────────────────────┐
│              条件注解过滤                                 │
│  @ConditionalOnClass                                    │
│  @ConditionalOnMissingBean                              │
│  @ConditionalOnProperty                                 │
└────────────────────┬────────────────────────────────────┘
                     │
                     ▼
┌─────────────────────────────────────────────────────────┐
│              实例化配置类                                 │
│         注册 Bean 到 AnnotationClassPathContext          │
└─────────────────────────────────────────────────────────┘
```

---

## 🏗️ 核心类设计

### 1. ImportSelector 接口

```java
package cn.code.autoconfigure;

/**
 * 导入选择器接口
 * 
 * @author jixiang
 */
public interface ImportSelector {

    /**
     * 选择要导入的配置类
     * 
     * @param metadata 注解元数据
     * @return 要导入的配置类名数组
     */
    String[] selectImports(AnnotationMetadata metadata);
}
```

---

### 2. EnableAutoConfigurationImportSelector 类

```java
package cn.code.autoconfigure;

import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.util.*;

/**
 * 自动配置导入选择器
 * 
 * 实现 ImportSelector 接口，负责：
 * 1. 读取 META-INF/spring.factories
 * 2. 解析自动配置类列表
 * 3. 应用条件注解过滤
 * 
 * @author jixiang
 */
public class EnableAutoConfigurationImportSelector implements ImportSelector {

    private static final String FACTORIES_RESOURCE_LOCATION = 
        "META-INF/spring.factories";

    private static final String ENABLE_AUTO_CONFIGURATION_KEY = 
        "org.springframework.boot.autoconfigure.EnableAutoConfiguration";

    @Override
    public String[] selectImports(AnnotationMetadata metadata) {
        // 1. 加载所有配置
        List<String> configurations = loadFactoryNames();

        // 2. 过滤（应用条件注解）
        configurations = filter(configurations);

        return configurations.toArray(new String[0]);
    }

    /**
     * 读取 spring.factories
     */
    private List<String> loadFactoryNames() {
        List<String> result = new ArrayList<>();
        try {
            Enumeration<URL> urls = 
                Thread.currentThread().getContextClassLoader()
                    .getResources(FACTORIES_RESOURCE_LOCATION);

            while (urls.hasMoreElements()) {
                URL url = urls.nextElement();
                Properties properties = loadProperties(url);
                String factories = properties.getProperty(
                    ENABLE_AUTO_CONFIGURATION_KEY
                );

                if (factories != null && !factories.trim().isEmpty()) {
                    String[] factoryArray = factories.split(",");
                    for (String factory : factoryArray) {
                        String trimmed = factory.trim();
                        if (!trimmed.isEmpty() && !trimmed.startsWith("#")) {
                            result.add(trimmed);
                        }
                    }
                }
            }
        } catch (IOException e) {
            // 边界处理：spring.factories 不存在时静默跳过
            System.out.println(
                "Warning: spring.factories not found, skip auto-configuration"
            );
        }
        return result;
    }

    /**
     * 加载 Properties 文件
     */
    private Properties loadProperties(URL url) throws IOException {
        Properties properties = new Properties();
        try (InputStream is = url.openStream()) {
            properties.load(is);
        }
        return properties;
    }

    /**
     * 过滤配置类（应用条件注解）
     */
    private List<String> filter(List<String> configurations) {
        List<String> filtered = new ArrayList<>();
        for (String config : configurations) {
            if (matchesConditions(config)) {
                filtered.add(config);
            }
        }
        return filtered;
    }

    /**
     * 判断是否满足条件
     */
    private boolean matchesConditions(String configClassName) {
        try {
            Class<?> configClass = Class.forName(configClassName);
            // 获取@Conditional 注解并判断
            // 简化版：返回 true
            return true;
        } catch (ClassNotFoundException e) {
            System.out.println(
                "Warning: Config class not found: " + configClassName
            );
            return false;
        }
    }
}
```

---

### 3. Condition 接口

```java
package cn.code.autoconfigure;

/**
 * 条件接口
 * 
 * 所有条件注解都需要实现此接口
 * 
 * @author jixiang
 */
public interface Condition {

    /**
     * 判断是否满足条件
     * 
     * @param context 条件上下文
     * @param metadata 注解元数据
     * @return true-满足条件，false-不满足
     */
    boolean matches(ConditionContext context, AnnotationMetadata metadata);
}
```

---

### 4. ConditionContext 接口

```java
package cn.code.autoconfigure;

/**
 * 条件上下文接口
 * 
 * 提供条件判断所需的环境信息
 * 
