package cn.code.annotation;

import cn.code.autoconfigure.EnableAutoConfigurationImportSelector;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 启用自动配置注解
 * 
 * 作用：标记配置类，触发自动配置机制
 * 原理：通过@Import 导入 EnableAutoConfigurationImportSelector
 * 
 * @author jixiang
 */
@Target(ElementType.TYPE)
@Retention(RetentionPolicy.RUNTIME)
@Import(EnableAutoConfigurationImportSelector.class)
public @interface EnableAutoConfiguration {

    /**
     * 排除的自动配置类
     * 
     * @return 要排除的类数组
     */
    Class<?>[] exclude() default {};
}

package cn.code.annotation;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 导入配置类注解
 * 
 * 作用：导入其他配置类到当前配置中
 * 原理：被导入的类会被实例化并注册到 IOC 容器
 * 
 * @author jixiang
 */
@Target(ElementType.TYPE)
@Retention(RetentionPolicy.RUNTIME)
public @interface Import {

    /**
     * 要导入的配置类
     * 
     * @return 配置类数组
     */
    Class<?>[] value();
}

package cn.code.annotation;

import cn.code.autoconfigure.Condition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 条件注解
 * 
 * 作用：标注在配置类或 Bean 方法上，只有满足条件时才会加载
 * 原理：通过 Condition 接口的 matches 方法判断是否满足条件
 * 
 * @author jixiang
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
public @interface Conditional {

    /**
     * 条件实现类
     * 
     * @return Condition 实现类
     */
    Class<? extends Condition> value();
}

package cn.code.annotation;

import cn.code.autoconfigure.OnClassCondition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 类路径条件注解
 * 
 * 作用：当类路径存在指定类时，配置类或 Bean 才会被加载
 * 
 * @author jixiang
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Conditional(OnClassCondition.class)
public @interface ConditionalOnClass {

    /**
     * 需要存在的类
     * 
     * @return 类数组
     */
    Class<?>[] value() default {};

    /**
     * 需要存在的类名（字符串形式）
     * 
     * @return 类名数组
     */
    String[] name() default {};
}

package cn.code.annotation;

import cn.code.autoconfigure.OnBeanCondition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * Bean 缺失条件注解
 * 
 * 作用：当容器中不存在指定 Bean 时，配置类或 Bean 才会被加载
 * 
 * @author jixiang
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Conditional(OnBeanCondition.class)
public @interface ConditionalOnMissingBean {

    /**
     * 需要检查的 Bean 类型
     * 
     * @return 类型数组
     */
    Class<?>[] value() default {};

    /**
     * 需要检查的 Bean 名称
     * 
     * @return 名称数组
     */
    String[] name() default {};
}

package cn.code.annotation;

import cn.code.autoconfigure.OnPropertyCondition;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * 属性条件注解
 * 
 * 作用：当配置属性满足条件时，配置类或 Bean 才会被加载
 * 属性来源：System.getProperty() + application.properties
 * 
 * @author jixiang
 */
@Target({ElementType.TYPE, ElementType.METHOD})
@Retention(RetentionPolicy.RUNTIME)
@Conditional(OnPropertyCondition.class)
public @interface ConditionalOnProperty {

    /**
     * 属性前缀
     * 
     * @return 前缀
     */
    String prefix() default "";

    /**
     * 属性名
     * 
     * @return 属性名
     */
    String name();

    /**
     * 匹配的值
     * 
     * @return 期望的属性值
     */
    String havingValue() default "true";

    /**
     * 属性不存在时是否匹配
     * 
     * @return true-属性不存在时也匹配，false-不匹配
     */
    boolean matchIfMissing() default false;
}

package cn.code.autoconfigure;

/**
 * 导入选择器接口
 * 
 * @author jixiang
 */
public interface ImportSelector {

    /**
     * 选择要导入的配置类
     * 
     * @param metadata 注解元数据
     * @return 要导入的配置类名数组
     */
    String[] selectImports(AnnotationMetadata metadata);
}

package cn.code.autoconfigure;

import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.util.*;

/**
 * 自动配置导入选择器
 * 
 * 实现 ImportSelector 接口，负责：
 * 1. 读取 META-INF/spring.factories
 * 2. 解析自动配置类列表
 * 3. 应用条件注解过滤
 * 
 * @author jixiang
 */
public class EnableAutoConfigurationImportSelector implements ImportSelector {

    private static final String FACTORIES_RESOURCE_LOCATION = 
        "META-INF/spring.factories";

    private static final String ENABLE_AUTO_CONFIGURATION_KEY = 
        "org.springframework.boot.autoconfigure.EnableAutoConfiguration";

    @Override
    public String[] selectImports(AnnotationMetadata metadata) {
        // 1. 加载所有配置
        List<String> configurations = loadFactoryNames();

        // 2. 过滤（应用条件注解）
        configurations = filter(configurations);

        return configurations.toArray(new String[0]);
    }

    /**
     * 读取 spring.factories
     */
    private List<String> loadFactoryNames() {
        List<String> result = new ArrayList<>();
        try {
            Enumeration<URL> urls = 
                Thread.currentThread().getContextClassLoader()
                    .getResources(FACTORIES_RESOURCE_LOCATION);

            while (urls.hasMoreElements()) {
                URL url = urls.nextElement();
                Properties properties = loadProperties(url);
                String factories = properties.getProperty(
                    ENABLE_AUTO_CONFIGURATION_KEY
                );

                if (factories != null && !factories.trim().isEmpty()) {
                    String[] factoryArray = factories.split(",");
                    for (String factory : factoryArray) {
                        String trimmed = factory.trim();
                        if (!trimmed.isEmpty() && !trimmed.startsWith("#")) {
                            result.add(trimmed);
                        }
                    }
                }
            }
        } catch (IOException e) {
            // 边界处理：spring.factories 不存在时静默跳过
            System.out.println(
                "Warning: spring.factories not found, skip auto-configuration"
            );
        }
        return result;
    }

    /**
     * 加载 Properties 文件
     */
    private Properties loadProperties(URL url) throws IOException {
        Properties properties = new Properties();
        try (InputStream is = url.openStream()) {
            properties.load(is);
        }
        return properties;
    }

    /**
     * 过滤配置类（应用条件注解）
     */
    private List<String> filter(List<String> configurations) {
        List<String> filtered = new ArrayList<>();
        for (String config : configurations) {
            if (matchesConditions(config)) {
                filtered.add(config);
            } else {
                System.out.println("Auto-configuration skipped: " + config);
            }
        }
        return filtered;
    }

    /**
     * 判断是否满足条件
     */
    private boolean matchesConditions(String configClassName) {
        try {
            Class<?> configClass = Class.forName(configClassName);

            // 获取@Conditional 注解
            Conditional[] conditionals = 
                configClass.getAnnotationsByType(Conditional.class);

            // 没有条件注解，默认满足
            if (conditionals == null || conditionals.length == 0) {
                return true;
            }

            // 所有条件都必须满足（AND 逻辑）
            for (Conditional conditional : conditionals) {
                Class<? extends Condition> conditionClass = conditional.value();
                Condition condition = conditionClass.newInstance();

                if (!condition.matches(null, null)) {
                    return false;
                }
            }

            return true;

        } catch (ClassNotFoundException e) {
            System.out.println(
                "Warning: Config class not found: " + configClassName
            );
            return false;
        } catch (Exception e) {
            System.out.println(
                "Warning: Failed to process config class: " + configClassName + 
                ", error: " + e.getMessage()
            );
            return false;
        }
    }
}

package cn.code.autoconfigure;

/**
 * 条件接口
 * 
 * 所有条件注解都需要实现此接口
 * 
 * @author jixiang
 */
public interface Condition {

    /**
     * 判断是否满足条件
     * 
     * @param context 条件上下文
     * @param metadata 注解元数据
     * @return true-满足条件，false-不满足
     */
    boolean matches(ConditionContext context, AnnotationMetadata metadata);
}

package cn.code.autoconfigure;

/**
 * 条件上下文接口
 * 
 * 提供条件判断所需的环境信息
 * 
 * @author jixiang
 */
public interface ConditionContext {

    /**
     * 获取 ClassLoader
     */
    ClassLoader getClassLoader();

    /**
     * 检查容器中是否包含指定 Bean
     */
    boolean containsBean(String beanName);

    /**
     * 获取配置属性
     */
    String getProperty(String key);

    /**
     * 获取 Bean 工厂
     */
    BeanFactory getBeanFactory();
}

package cn.code.autoconfigure;

/**
 * Bean 工厂接口
 * 
 * @author jixiang
 */
public interface BeanFactory {

    /**
     * 检查容器中是否包含指定 Bean
     */
    boolean containsBean(String name);

    /**
     * 获取 Bean 实例
     */
    Object getBean(String name);

    /**
     * 注册 Bean
     */
    void registerBean(String name, Object bean);
}

package cn.code.autoconfigure;

import java.util.HashMap;
import java.util.Map;

/**
 * 注解元数据
 * 
 * 用于存储注解的相关信息
 * 
 * @author jixiang
 */
public class AnnotationMetadata {

    private String className;
    private Map<String, Object> attributes = new HashMap<>();

    public AnnotationMetadata(String className) {
        this.className = className;
    }

    public String getClassName() {
        return className;
    }

    /**
     * 获取注解属性
     */
    public Map<String, Object> getAnnotationAttributes(Class<?> annotationType) {
        return new HashMap<>(attributes);
    }

    /**
     * 检查是否有指定注解
     */
    public boolean hasAnnotation(Class<?> annotationType) {
        return true;
    }

    public static AnnotationMetadata from(Class<?> cls) {
        return new AnnotationMetadata(cls.getName());
    }
}

package cn.code.autoconfigure;

/**
 * 类路径条件判断实现
 * 
 * 作用：判断类路径是否存在指定类
 * 
 * @author jixiang
 */
public class OnClassCondition implements Condition {

    @Override
    public boolean matches(ConditionContext context, AnnotationMetadata metadata) {
        // 简化实现
        // 实际需要从 metadata 获取@ConditionalOnClass 注解的属性
        // 然后检查类路径是否存在这些类
        return true;
    }
}

package cn.code.autoconfigure;

/**
 * Bean 缺失条件判断实现
 * 
 * 作用：判断容器中是否不存在指定 Bean
 * 
 * @author jixiang
 */
public class OnBeanCondition implements Condition {

    @Override
    public boolean matches(ConditionContext context, AnnotationMetadata metadata) {
        // 简化实现
        // 实际需要从 metadata 获取@ConditionalOnMissingBean 注解的属性
        // 然后检查容器是否不存在这些 Bean
        if (context == null) {
            return true;
        }
        // Bean 不存在时返回 true（满足条件）
        return !context.containsBean("demoService");
    }
}

package cn.code.autoconfigure;

/**
 * 属性条件判断实现
 * 
 * 作用：判断配置属性是否满足条件
 * 
 * @author jixiang
 */
public class OnPropertyCondition implements Condition {

    @Override
    public boolean matches(ConditionContext context, AnnotationMetadata metadata) {
        // 简化实现
        // 实际需要从 metadata 获取@ConditionalOnProperty 注解的属性
        // 然后检查属性值是否匹配
        if (context == null) {
            return true;
        }

        String value = context.getProperty("demo.enabled");
        return value == null || "true".equals(value);
    }
}

