package cn.code.starter.demo;

import cn.code.annotation.ConditionalOnClass;
import cn.code.annotation.ConditionalOnProperty;

/**
 * 示例自动配置类
 * 
 * 配置说明：
 * 1. @ConditionalOnClass - 当 DemoService 在类路径时加载
 * 2. @ConditionalOnProperty - 当 demo.enabled=true 时加载（默认 true）
 * 
 * @author jixiang
 */
@ConditionalOnClass(DemoService.class)
@ConditionalOnProperty(
    prefix = "demo",
    name = "enabled",
    havingValue = "true",
    matchIfMissing = true
)
public class DemoAutoConfiguration {

    /**
     * 创建 DemoService Bean
     * 
     * @return DemoService 实例
     */
    public DemoService demoService() {
        return new DemoService();
    }
}
